import json, time, urllib.parse, urllib.request
from collections import OrderedDict
from pathlib import Path

USER_AGENT='OpenAkari-Codex/0.1 (mailto:research@example.com)'
CROSSREF='https://api.crossref.org/works'
CONTAINER='Advances in Neural Information Processing Systems'
KEYWORDS=['multi-agent','multi agent','agent','agents','coordination','communication','cooperative','teamwork','collaboration','reinforcement learning']
QUERIES=['multi-agent','agent','cooperative','coordination','communication','teamwork','collaboration','reinforcement learning']

def fetch(params):
    url=CROSSREF+'?'+urllib.parse.urlencode(params)
    req=urllib.request.Request(url, headers={'User-Agent':USER_AGENT})
    with urllib.request.urlopen(req, timeout=20) as resp:
        return json.load(resp)

def normalize_title(item):
    return ' '.join(((item.get('title') or [''])[0]).split())

def authors(item):
    names=[]
    for a in item.get('author',[]):
        full=' '.join(x for x in [a.get('given','').strip(), a.get('family','').strip()] if x)
        if full:
            names.append(full)
    return ', '.join(names)

def year_of(item):
    for key in ('published-print','published-online','issued'):
        date=item.get(key,{}).get('date-parts')
        if date and date[0]:
            return str(date[0][0])
    return 'unknown'

def score(title):
    lower=title.lower()
    return sum(1 for kw in KEYWORDS if kw in lower)

def classify(title):
    lower=title.lower()
    tags=[]
    if any(k in lower for k in ['framework','system','collaboration','assistant']): tags.append('Architecture')
    if any(k in lower for k in ['coordination','teamwork','allocation']): tags.append('Coordination')
    if any(k in lower for k in ['communication','message','memory']): tags.append('Communication')
    if any(k in lower for k in ['benchmark','evaluation','assessing']): tags.append('Evaluation')
    if any(k in lower for k in ['software','mathematical','mobile','device','health']): tags.append('Application')
    if any(k in lower for k in ['game','regret','equilibr','learning']): tags.append('Theory/MARL')
    if not tags: tags.append('Unclassified')
    return tags

year_to_rows={}
year_to_notes={}
for year in (2024, 2025):
    seen=OrderedDict(); notes=[]
    for q in QUERIES:
        params={'query':q,'query.container-title':CONTAINER,'filter':f'from-pub-date:{year}-01-01,until-pub-date:{year}-12-31','rows':'50'}
        data=fetch(params)
        items=data.get('message',{}).get('items',[])
        matched=0
        for item in items:
            container=(item.get('container-title') or [''])[0]
            title=normalize_title(item)
            if not title: continue
            if 'advances in neural information processing systems' not in container.lower():
                continue
            matched += 1
            if score(title) <= 0:
                continue
            doi=item.get('DOI','')
            key=doi or title.lower()
            if key in seen: continue
            seen[key]={'title':title,'authors':authors(item),'year':year_of(item),'link':f'https://doi.org/{doi}' if doi else item.get('URL',''),'tags':classify(title),'query':q}
        notes.append(f"query={q!r}: {len(items)} items returned, {matched} with NeurIPS container-title")
    rows=sorted(seen.values(), key=lambda x:(-score(x['title']), x['title'].lower()))
    if year==2025 and not rows:
        notes.append('No NeurIPS 2025 records survived venue-constrained Crossref retrieval in this session; likely indexing lag or proceedings metadata mismatch.')
    year_to_rows[year]=rows
    year_to_notes[year]=notes

lines=['# NeurIPS 2024-2025 Multi-Agent candidate list','',
'Source: Crossref `works` API queried via inline Python in this session using the same retrieval logic as `projects/multi-agent-survey/scripts/harvest_neurips_crossref.py`.','',
'Method:','- Venue filter: container-title contains `Advances in Neural Information Processing Systems`.','- Year filter: publication year 2024 and 2025 separately.',f"- Query set: {', '.join(QUERIES)}.",'- Relevance heuristic: keep titles containing at least one agent/MAS-related keyword; assign lightweight topic tags from title tokens.','- Caveat: this is a retrieval snapshot, not a claim of exhaustive conference coverage.','',f"Total harvested candidates: {sum(len(v) for v in year_to_rows.values())}.",'']
for year in sorted(year_to_rows):
    lines += [f'## {year}','','Retrieval notes:']
    lines += [f'- {n}' for n in year_to_notes[year]]
    lines += ['']
    rows=year_to_rows[year]
    if not rows:
        lines += ['No candidates harvested for this year in the current Crossref snapshot.','']
        continue
    for i,row in enumerate(rows,1):
        lines += [f"{i}. **{row['title']}**",f"   - Authors: {row['authors'] or 'not returned by Crossref'}",f"   - Link: {row['link']}",f"   - Tags: {', '.join(row['tags'])}",f"   - Retrieved via query: `{row['query']}`"]
    lines += ['']

out=Path('projects/multi-agent-survey/literature/neurips-2024-2025.md')
out.parent.mkdir(parents=True, exist_ok=True)
out.write_text('\n'.join(lines), encoding='utf-8')
print('wrote', out)
for year, rows in year_to_rows.items():
    print(year, len(rows))
